create table localisations (id int primary key, numero_unique varchar(256), adresse_ip varchar(256), dbms varchar(50), nom_localisation varchar(50) UNIQUE NOT NULL, description_lieu varchar(50), quartier varchar(50), ville varchar(50), province_etat varchar(50), pays varchar(50), boite_postale varchar(50), date_ouverture date, email varchar(50), numero_telephone_1 varchar(28), numero_telephone_2 varchar(28));
